// Origami Tessellation
// Adapted from GenerativeArtGallery / artwork14

let ogTiles = [];
let ogScrollY = 0;
let ogPrevSize = '';

function ogMake(ts) {
  let tiles = [];
  let cols = Math.ceil(400 / ts) + 1;
  let rows = Math.ceil(400 / ts) + 2;
  for (let r = -1; r < rows; r++) {
    for (let c = 0; c < cols; c++) {
      tiles.push({
        c: c, r: r,
        x: c * ts, y: r * ts,
        fa: Math.random(),
        target: Math.random(),
        spd: 0.008 + Math.random() * 0.018,
        ftype: Math.floor(Math.random() * 4),
        hOff: (Math.random() - 0.5) * 40
      });
    }
  }
  return tiles;
}

p.setup = function() {
  p.createCanvas(400, 400);
  p.colorMode(p.HSB, 360, 100, 100, 100);
  p.frameRate(30);
  ogTiles = ogMake(80);
};

p.draw = function() {
  let foldStr  = p.getSynthVar('fold_type') || 'mixed';
  let sizeStr  = p.getSynthVar('tile_size') || 'medium';
  let speedStr = p.getSynthVar('animation_speed') || 'medium';
  let colorStr = p.getSynthVar('color_scheme') || 'pastel';

  let ts       = sizeStr === 'small' ? 50 : sizeStr === 'medium' ? 80 : 120;
  let spdMult  = speedStr === 'slow' ? 0.35 : speedStr === 'medium' ? 1 : 2.5;

  if (sizeStr !== ogPrevSize) { ogTiles = ogMake(ts); ogScrollY = 0; ogPrevSize = sizeStr; }

  let pals = {
    pastel: [200, 38, 95],
    jewel:  [258, 72, 84],
    warm:   [28,  62, 90],
    mono:   [0,   0,  84]
  };
  let pal = pals[colorStr] || pals.pastel;

  p.noStroke();
  p.fill(pal[0], pal[1] * 0.28, pal[2] * 0.88);
  p.rect(0, 0, 400, 400);

  ogScrollY = (ogScrollY + 0.35 * spdMult) % ts;
  let totalRows = Math.ceil(400 / ts) + 2;

  ogTiles.forEach(function(tile) {
    tile.fa += (tile.target - tile.fa) * tile.spd * spdMult;
    if (Math.abs(tile.fa - tile.target) < 0.015) tile.target = Math.random();

    let y = tile.y + ogScrollY;
    if (y > 400 + ts) tile.y -= totalRows * ts;

    let ft   = foldStr === 'valley' ? 0 : foldStr === 'mountain' ? 1 : foldStr === 'waterbomb' ? 2 : foldStr === 'twist' ? 3 : tile.ftype;
    let h    = (pal[0] + tile.hOff + 360) % 360;
    let s    = pal[1];
    let b    = pal[2];
    let fa   = tile.fa;
    let half = ts / 2;

    p.push();
    p.translate(tile.x + half, y + half);

    // Drop shadow
    p.noStroke();
    p.fill(h, s * 0.7, b * 0.2, 22);
    p.ellipse(3, 5, ts * 0.7, ts * 0.28);

    if (ft === 0) {
      // Valley fold: left dark, right light
      let indent = half * fa * 0.5;
      p.stroke(h, s, b - 38, 28); p.strokeWeight(0.5);
      p.fill(h, s + 12, b - 22, 100);
      p.beginShape(); p.vertex(-half,-half); p.vertex(0,-half+indent*0.4); p.vertex(0,half-indent*0.4); p.vertex(-half,half); p.endShape(p.CLOSE);
      p.fill(h, s - 10, b + 6, 100);
      p.beginShape(); p.vertex(half,-half); p.vertex(0,-half+indent*0.4); p.vertex(0,half-indent*0.4); p.vertex(half,half); p.endShape(p.CLOSE);

    } else if (ft === 1) {
      // Mountain: top bright, bottom dark
      let peak = -half + half * fa * 0.62;
      p.noStroke();
      p.fill(h, s - 14, b + 14, 100);
      p.beginShape(); p.vertex(-half,-half); p.vertex(half,-half); p.vertex(half*0.28,peak); p.vertex(-half*0.28,peak); p.endShape(p.CLOSE);
      p.fill(h, s, b - 12, 100);
      p.beginShape(); p.vertex(-half,half); p.vertex(half,half); p.vertex(half*0.28,peak); p.vertex(-half*0.28,peak); p.endShape(p.CLOSE);

    } else if (ft === 2) {
      // Waterbomb: 4 triangles from edge midpoints to centre point
      let cp = half * fa * 0.58;
      p.noStroke();
      p.fill(h,      s,      b + 10, 100); p.triangle(-half,-half, half,-half, 0,-cp);
      p.fill(h + 6,  s + 10, b - 5,  100); p.triangle(half,-half,  half,half,  cp,0);
      p.fill(h + 12, s,      b,      100); p.triangle(half,half,  -half,half,  0,cp);
      p.fill(h - 6,  s + 8,  b + 5,  100); p.triangle(-half,half, -half,-half, -cp,0);

    } else {
      // Twist: base square + rotated inner square
      let ang = fa * p.PI * 0.5;
      let ir  = half * 0.65;
      p.noStroke();
      p.fill(h, s, b - 16, 100);
      p.beginShape(); p.vertex(-half,-half); p.vertex(half,-half); p.vertex(half,half); p.vertex(-half,half); p.endShape(p.CLOSE);
      p.fill((h + 28) % 360, Math.min(100, s + 14), b, 100);
      p.push(); p.rotate(ang);
      p.beginShape();
      for (let k = 0; k < 4; k++) { let a = k * p.HALF_PI + p.PI / 4; p.vertex(Math.cos(a) * ir, Math.sin(a) * ir); }
      p.endShape(p.CLOSE);
      p.pop();
    }

    p.pop();
  });
};
